const raw = ($('When Called').item.json.mensagem || '').toLowerCase().trim();
const norm = raw.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const hasCancel = /\b(cancel|nao vou|nao posso|nao consigo|desisti|nao darei|n[aã]o\s+vou)\b/.test(norm)
  || /\bnao\b/.test(norm) && !/\bnao\s+(sei|tenho|lembro)\b/.test(norm);
const hasReschedule = /\b(reagend|remarc|adiar|outro\s+(dia|hor[aá]rio)|transfer|mudar.*hor|trocar.*hor)\b/.test(norm);
const hasConfirm = /\b(sim|confirm|ok|claro|perfeito|combinado|estarei|vou\s+sim|estou|certo|beleza|pode\s+ser|tudo\s+certo|positivo)\b/.test(norm)
  || /^(s|sim|👍|✅|✔)$/i.test(raw)
  || /[👍✅✔🆗]/.test(raw);
let intent = 'unknown';
if (hasCancel && !hasConfirm) intent = 'cancel';
else if (hasReschedule) intent = 'reschedule';
else if (hasConfirm) intent = 'confirm';
const apt = $('Find Upcoming Appointment').item.json;
return {
  json: {
    intent,
    appointment_id: apt.id,
    appointment_date: apt.appointment_date,
    doctor_name: apt.doctor_name,
    patient_name: apt.patient_name || 'Paciente',
    raw_message: raw
  }
};

